+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
+#[serde(rename_all = "kebab-case")]
+enum LiveTruthKnowledgeState {
+    Offline,
+    NodeLocal,
+    MeshBacked,
+    Degraded,
+    FallbackDerived,
+}
+
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
+#[serde(rename_all = "kebab-case")]
+enum LiveTruthResolverBranch {
+    OfflineManifest,
+    OfflineMirror,
+    InstallVerification,
+    LivePlacementPolicy,
+    LiveArtifactOnly,
+    LiveRuntimeOnly,
+    LiveRuntimeDegraded,
+    PostInstallStatusUnavailable,
+}
+
+#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
+struct LiveTruthResolution {
+    knowledge_state: LiveTruthKnowledgeState,
+    resolver_branch: LiveTruthResolverBranch,
+    authoritative_scope: &'static str,
+    mesh_backed: bool,
+    degraded: bool,
+    fallback_derived: bool,
+    reason: String,
+}
+
+impl LiveTruthResolution {
+    fn offline(
+        authoritative_scope: &'static str,
+        resolver_branch: LiveTruthResolverBranch,
+        reason: impl Into<String>,
+    ) -> Self {
+        Self {
+            knowledge_state: LiveTruthKnowledgeState::Offline,
+            resolver_branch,
+            authoritative_scope,
+            mesh_backed: false,
+            degraded: false,
+            fallback_derived: false,
+            reason: reason.into(),
+        }
+    }
+
+    fn node_local(
+        authoritative_scope: &'static str,
+        resolver_branch: LiveTruthResolverBranch,
+        reason: impl Into<String>,
+    ) -> Self {
+        Self {
+            knowledge_state: LiveTruthKnowledgeState::NodeLocal,
+            resolver_branch,
+            authoritative_scope,
+            mesh_backed: false,
+            degraded: false,
+            fallback_derived: false,
+            reason: reason.into(),
+        }
+    }
+
+    fn mesh_backed(
+        authoritative_scope: &'static str,
+        resolver_branch: LiveTruthResolverBranch,
+        reason: impl Into<String>,
+    ) -> Self {
+        Self {
+            knowledge_state: LiveTruthKnowledgeState::MeshBacked,
+            resolver_branch,
+            authoritative_scope,
+            mesh_backed: true,
+            degraded: false,
+            fallback_derived: false,
+            reason: reason.into(),
+        }
+    }
+
+    fn degraded(
+        authoritative_scope: &'static str,
+        resolver_branch: LiveTruthResolverBranch,
+        mesh_backed: bool,
+        reason: impl Into<String>,
+    ) -> Self {
+        Self {
+            knowledge_state: LiveTruthKnowledgeState::Degraded,
+            resolver_branch,
+            authoritative_scope,
+            mesh_backed,
+            degraded: true,
+            fallback_derived: false,
+            reason: reason.into(),
+        }
+    }
+
+    fn fallback_derived(
+        authoritative_scope: &'static str,
+        resolver_branch: LiveTruthResolverBranch,
+        degraded: bool,
+        reason: impl Into<String>,
+    ) -> Self {
+        Self {
+            knowledge_state: LiveTruthKnowledgeState::FallbackDerived,
+            resolver_branch,
+            authoritative_scope,
+            mesh_backed: false,
+            degraded,
+            fallback_derived: true,
+            reason: reason.into(),
+        }
+    }
+}
+
